//! VHDL-2008 emission for combinatorial resolution-lift (parity with Rust reference).

pub fn emit_resolution_lift_vhdl() -> String {
    r#"-- Generated by gnosis-rtl-bridge; parity with distributed_inference::attention_closure_lift
library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

entity gnosis_resolution_lift_fsm_v0 is
  port (
    i_heads                 : in  unsigned(3 downto 0);
    i_coupling              : in  unsigned(15 downto 0);
    i_observer_resolution   : in  unsigned(15 downto 0);
    i_residue_threshold     : in  unsigned(15 downto 0);
    o_lift                  : out std_logic;
    o_after_observer_resolution : out unsigned(15 downto 0)
  );
end entity gnosis_resolution_lift_fsm_v0;

architecture rtl of gnosis_resolution_lift_fsm_v0 is
  constant TRITON_PHASE : natural := 3;

  function head_phase(head : natural) return natural is
  begin
    return TRITON_PHASE * (head + 1);
  end function;

  function coord_at_res(head : natural; res : natural) return natural is
    variable denom : natural;
  begin
    if res < 1 then
      denom := 1;
    else
      denom := res;
    end if;
    return head_phase(head) mod denom;
  end function;

  function trace_separated8(
    t0, t1, t2, t3, t4, t5, t6, t7 : natural;
    heads : natural
  ) return boolean is
    type tarr is array (0 to 7) of natural;
    variable tr : tarr;
    variable i, j : natural;
  begin
    tr := (t0, t1, t2, t3, t4, t5, t6, t7);
    for ii in 0 to heads - 1 loop
      for jj in ii + 1 to heads - 1 loop
        if tr(ii) = tr(jj) then
          return false;
        end if;
      end loop;
    end loop;
    return true;
  end function;

begin
  comb : process (i_heads, i_coupling, i_observer_resolution, i_residue_threshold)
    variable heads_v, coupling_v, obs_v, thr_v : natural;
    variable multi_head, source_res, unresolved : natural;
    variable obs_eff : natural;
    variable t0, t1, t2, t3, t4, t5, t6, t7 : natural;
    variable sep : boolean;
    variable should_lift : boolean;
    variable after_obs : natural;
  begin
    heads_v   := to_integer(i_heads);
    coupling_v := to_integer(i_coupling);
    obs_v     := to_integer(i_observer_resolution);
    thr_v     := to_integer(i_residue_threshold);

    if heads_v < 0 then
      heads_v := 0;
    end if;
    if heads_v > 8 then
      heads_v := 8;
    end if;

    if obs_v < 1 then
      obs_eff := 1;
    else
      obs_eff := obs_v;
    end if;

    multi_head  := TRITON_PHASE * heads_v;
    source_res  := multi_head + coupling_v;
    if source_res >= obs_eff then
      unresolved := source_res - obs_eff;
    else
      unresolved := 0;
    end if;

    t0 := coord_at_res(0, obs_eff);
    t1 := coord_at_res(1, obs_eff);
    t2 := coord_at_res(2, obs_eff);
    t3 := coord_at_res(3, obs_eff);
    t4 := coord_at_res(4, obs_eff);
    t5 := coord_at_res(5, obs_eff);
    t6 := coord_at_res(6, obs_eff);
    t7 := coord_at_res(7, obs_eff);

    if heads_v < 1 then
      sep := true;
    else
      sep := trace_separated8(t0, t1, t2, t3, t4, t5, t6, t7, heads_v);
    end if;

    if thr_v < 1 then
      should_lift := (not sep) or (unresolved >= 1);
    else
      should_lift := (not sep) or (unresolved >= thr_v);
    end if;

    if should_lift then
      o_lift <= '1';
      after_obs := source_res;
    else
      o_lift <= '0';
      after_obs := obs_v;
    end if;

    if after_obs > 65535 then
      o_after_observer_resolution <= to_unsigned(65535, 16);
    else
      o_after_observer_resolution <= to_unsigned(after_obs, 16);
    end if;
  end process comb;
end architecture rtl;
"#
    .to_string()
}

pub fn emit_resolution_lift_tb_vhdl() -> String {
    r#"-- Testbench for gnosis_resolution_lift_fsm_v0 (GHDL)
library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

entity gnosis_resolution_lift_tb_v0 is
end entity;

architecture sim of gnosis_resolution_lift_tb_v0 is
  signal heads                 : unsigned(3 downto 0) := (others => '0');
  signal coupling              : unsigned(15 downto 0) := (others => '0');
  signal observer_resolution   : unsigned(15 downto 0) := (others => '0');
  signal residue_threshold     : unsigned(15 downto 0) := (others => '0');
  signal lift                  : std_logic;
  signal after_observer_resolution : unsigned(15 downto 0);
begin
  dut : entity work.gnosis_resolution_lift_fsm_v0
    port map (
      i_heads => heads,
      i_coupling => coupling,
      i_observer_resolution => observer_resolution,
      i_residue_threshold => residue_threshold,
      o_lift => lift,
      o_after_observer_resolution => after_observer_resolution
    );

  stim : process
  begin
    -- Vector 1: aeon eight-head alias -> lift to 24
    heads <= to_unsigned(8, 4);
    coupling <= to_unsigned(0, 16);
    observer_resolution <= to_unsigned(12, 16);
    residue_threshold <= to_unsigned(1, 16);
    wait for 1 ns;
    assert lift = '1' report "v1 lift expected" severity error;
    assert after_observer_resolution = to_unsigned(24, 16)
      report "v1 after_obs wrong" severity error;

    -- Vector 2: already lifted structured -> no lift, stays 24
    heads <= to_unsigned(8, 4);
    coupling <= to_unsigned(0, 16);
    observer_resolution <= to_unsigned(24, 16);
    residue_threshold <= to_unsigned(1, 16);
    wait for 1 ns;
    assert lift = '0' report "v2 no lift" severity error;
    assert after_observer_resolution = to_unsigned(24, 16)
      report "v2 after_obs" severity error;

    -- Vector 3: pink lifted closure -> no lift at 30
    heads <= to_unsigned(8, 4);
    coupling <= to_unsigned(6, 16);
    observer_resolution <= to_unsigned(30, 16);
    residue_threshold <= to_unsigned(1, 16);
    wait for 1 ns;
    assert lift = '0' report "v3 no lift" severity error;
    assert after_observer_resolution = to_unsigned(30, 16)
      report "v3 after_obs" severity error;

    report "gnosis_resolution_lift_tb_v0: PASS";
    wait;
  end process stim;
end architecture sim;
"#
    .to_string()
}
